from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    if not triples:
        return ""
    from collections import defaultdict

    # Group triples by subject
    subj_map = defaultdict(list)
    for t in triples:
        subj_map[t.subject].append((t.predicate, t.object))

    # Helper to render a single predicate‑object pair
    def render(p: str, o: str) -> str:
        if p in ("birthDate", "birthYear"):
            return f"was born in {o}"
        if p == "deathDate":
            return f"died on {o}"
        if p == "deathPlace":
            return f"died in {o}"
        if p == "birthPlace":
            return f"was born in {o}"
        if p == "origin":
            return f"originated from {o}"
        if p == "genre":
            return f"plays {o} music"
        if p == "instrument":
            return f"plays the {o}"
        if p == "occupation":
            return f"works as a {o}"
        if p == "nationality":
            return f"is from {o}"
        if p == "associatedBand/associatedMusicalArtist":
            return f"plays with {o}"
        if p == "recordLabel":
            return f"is signed to {o}"
        if p == "background":
            return f"has a background as {o}"
        if p == "activeYearsStartYear":
            return f"started activity in {o}"
        if p == "activeYearsEndYear":
            return f"ended activity in {o}"
        if p == "capital":
            return f"has capital {o}"
        if p == "leader":
            return f"{o} is the leader"
        if p == "leaderTitle":
            return f"the leader holds the title {o}"
        if p == "country":
            return f"is part of {o}"
        # default fallback
        return f"{p} {o}"

    # Predicates that link to another subject
    linking_preds = {"nationality", "origin", "country", "isPartOf"}

    sentences = []
    for subj, props in subj_map.items():
        # Separate linking and non‑linking predicates
        non_link = []
        link_clause = ""
        for p, o in props:
            if p in linking_preds and o in subj_map:
                # Build a relative clause for the linked subject
                linked_parts = []
                for lp, lo in subj_map[o]:
                    if lp == "leader":
                        linked_parts.append(f"{lo} is the leader")
                    elif lp == "capital":
                        linked_parts.append(f"its capital is {lo}")
                    elif lp == "populationDensity":
                        linked_parts.append(f"its population density is {lo}")
                linked_desc = ""
                if linked_parts:
                    linked_desc = f", where {' and '.join(linked_parts)}"
                # Choose appropriate relative pronoun
                rel_pronoun = "who is from" if p in {"nationality", "origin", "country"} else "which is part of"
                link_clause = f", {rel_pronoun} {o}{linked_desc}"
            else:
                non_link.append(render(p, o))

        # Assemble the sentence for this subject
        if non_link:
            base = f"{subj} " + ", ".join(non_link)
        else:
            base = subj

        sentence = base + link_clause
        sentences.append(sentence)

    # Combine all subject sentences into one fluent paragraph
    if len(sentences) == 1:
        return sentences[0] + "."
    else:
        return " ".join(s + "." for s in sentences)

# EVOLVE-BLOCK-END

